import{c as a,a7 as r,y as e,B as s}from"./chunks/framework.3cjvm90C.js";const c=JSON.parse('{"title":"大模型训练效率度量：MFU 计算深度解析","description":"深入解析模型浮点运算利用率（MFU）的定义、Transformer 模型 FLOPs 推导及在昇腾平台上的计算方法","frontmatter":{"title":"大模型训练效率度量：MFU 计算深度解析","description":"深入解析模型浮点运算利用率（MFU）的定义、Transformer 模型 FLOPs 推导及在昇腾平台上的计算方法"},"headers":[],"relativePath":"ascend/mfu_calculation.md","filePath":"ascend/mfu_calculation.md","lastUpdated":1782456021000}'),h={name:"ascend/mfu_calculation.md"};function d(l,t,o,i,n,b){return r(),e("div",null,[...t[0]||(t[0]=[s('<h1 id="大模型训练效率度量-mfu-计算深度解析" tabindex="-1">大模型训练效率度量：MFU 计算深度解析 <a class="header-anchor" href="#大模型训练效率度量-mfu-计算深度解析" aria-label="Permalink to “大模型训练效率度量：MFU 计算深度解析”">​</a></h1><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to “概述”">​</a></h2><p>在深度学习领域，<strong>MFU (Model FLOPs Utilization，模型浮点运算利用率)</strong> 是衡量大模型训练效率的核心指标。它描述了模型在实际训练过程中有效利用硬件理论计算能力的程度。对于 GPT 和 Llama 等参数量巨大的 Transformer 模型，监控并优化 MFU 是提升训练吞吐量、降低算力成本的关键。</p><h2 id="_1-mfu-的核心概念" tabindex="-1">1. MFU 的核心概念 <a class="header-anchor" href="#_1-mfu-的核心概念" aria-label="Permalink to “1. MFU 的核心概念”">​</a></h2><h3 id="_1-1-定义" tabindex="-1">1.1 定义 <a class="header-anchor" href="#_1-1-定义" aria-label="Permalink to “1.1 定义”">​</a></h3><p>MFU 定义为模型在实际训练过程中每秒执行的有效浮点运算次数与硬件理论峰值算力的比值：</p><p>$$ MFU = \\frac{\\text{Actual FLOPs} }{\\text{Theoretical Peak FLOPs} } $$</p><h3 id="_1-2-关键要素" tabindex="-1">1.2 关键要素 <a class="header-anchor" href="#_1-2-关键要素" aria-label="Permalink to “1.2 关键要素”">​</a></h3><ul><li><strong>Actual FLOPs (实际达到的 FLOPs)</strong>：指模型执行前向传播（Forward）和反向传播（Backward）及优化器更新等所需的所有计算。</li><li><strong>Theoretical Peak FLOPs (硬件理论峰值)</strong>：硬件（如 NVIDIA H100 或 Ascend 910）在特定精度（如 FP16/BF16）下的标称最大吞吐量。</li></ul><h3 id="_1-3-核心意义" tabindex="-1">1.3 核心意义 <a class="header-anchor" href="#_1-3-核心意义" aria-label="Permalink to “1.3 核心意义”">​</a></h3><ul><li><strong>诊断瓶颈</strong>：低 MFU 通常意味着存在通信带宽瓶颈（Communication Bound）、内存带宽限制（Memory Bound）或算子实现效率低下。</li><li><strong>优化指导</strong>：通过调整 Batch Size、并行策略（TP/PP/DP）或使用混合精度训练来逼近硬件极限。</li></ul><h2 id="_2-transformer-模型的-flops-推导" tabindex="-1">2. Transformer 模型的 FLOPs 推导 <a class="header-anchor" href="#_2-transformer-模型的-flops-推导" aria-label="Permalink to “2. Transformer 模型的 FLOPs 推导”">​</a></h2><p>以标准的 GPT 架构为例，详细推导其在训练过程中每步所需的浮点运算量（FLOPs），为评估大模型训练效率提供理论基础。</p><h3 id="_2-1-flops-定义" tabindex="-1">2.1 FLOPs 定义 <a class="header-anchor" href="#_2-1-flops-定义" aria-label="Permalink to “2.1 FLOPs 定义”">​</a></h3><ul><li><strong>FLOPs</strong>：表示完成一次矩阵乘法所需的浮点操作次数。</li><li>对于一个 $A_{m \\times k} \\times B_{k \\times n}$ 的矩阵乘法： <ul><li>所需 FLOPs 数量为： $$2 \\times m \\times k \\times n$$</li><li>包含： <ul><li>$m \\times k \\times n$ 次乘法操作</li><li>$m \\times k \\times (n - 1)$ 次加法操作</li><li>总计约 $2mkn$</li></ul></li></ul></li></ul><h3 id="_2-2-transformer-层的-flops-分析" tabindex="-1">2.2 Transformer 层的 FLOPs 分析 <a class="header-anchor" href="#_2-2-transformer-层的-flops-分析" aria-label="Permalink to “2.2 Transformer 层的 FLOPs 分析”">​</a></h3><h4 id="符号定义" tabindex="-1">符号定义 <a class="header-anchor" href="#符号定义" aria-label="Permalink to “符号定义”">​</a></h4><table tabindex="0"><thead><tr><th><strong>符号</strong></th><th><strong>含义</strong></th><th><strong>符号</strong></th><th><strong>含义</strong></th></tr></thead><tbody><tr><td>$b$</td><td>Batch Size (批大小)</td><td>$h$</td><td>Hidden Dimension (隐藏层维度)</td></tr><tr><td>$s$</td><td>Sequence Length (序列长度)</td><td>$V$</td><td>Vocabulary Size (词表大小)</td></tr><tr><td>$L$</td><td>Number of Layers (层数)</td><td>$4h$</td><td>MLP 中间层维度</td></tr></tbody></table><h4 id="_1-self-attention-模块-flops" tabindex="-1">1. Self-Attention 模块 FLOPs <a class="header-anchor" href="#_1-self-attention-模块-flops" aria-label="Permalink to “1. Self-Attention 模块 FLOPs”">​</a></h4><h5 id="公式" tabindex="-1">公式： <a class="header-anchor" href="#公式" aria-label="Permalink to “公式：”">​</a></h5><p>$$ Q, K, V = xW_Q, xW_K, xW_V \\ \\text{attn_score} = \\text{softmax}\\left(\\frac{QK^T}{\\sqrt{h} }\\right) \\ \\text{context} = \\text{attn_score} * V \\ \\text{proj} = \\text{context} * W_O $$</p><h5 id="flops-计算" tabindex="-1">FLOPs 计算： <a class="header-anchor" href="#flops-计算" aria-label="Permalink to “FLOPs 计算：”">​</a></h5><table tabindex="0"><thead><tr><th>操作</th><th>输入形状</th><th>输出形状</th><th>FLOPs</th></tr></thead><tbody><tr><td>$[b,s,h] \\to [b,s,h]$（Q/K/V 投影）</td><td>$[b,s,h] \\times [h,h]$</td><td>$[b,s,h]$</td><td>$3 \\times 2bs h^2 = 6bsh^2$</td></tr><tr><td>$[b,s,h] \\to [b,s,h]$（QKᵀ）</td><td>$[b,s,h] \\times [b,h,s]$</td><td>$[b,s,s]$</td><td>$2bs^2h$</td></tr><tr><td>$[b,s,s] \\to [b,s,h]$（attention × V）</td><td>$[b,s,s] \\times [b,s,h]$</td><td>$[b,s,h]$</td><td>$2bs^2h$</td></tr><tr><td>$[b,s,h] \\to [b,s,h]$（投影回 hidden）</td><td>$[b,s,h] \\times [h,h]$</td><td>$[b,s,h]$</td><td>$2bsh^2$</td></tr></tbody></table><blockquote><p>🔹 总计 Attention FLOPs： $$6bsh^2 + 2bs^2h + 2bs^2h + 2bsh^2 = 8bsh^2 + 4bs^2h$$</p></blockquote><h4 id="_2-mlp-模块-flops" tabindex="-1">2. MLP 模块 FLOPs <a class="header-anchor" href="#_2-mlp-模块-flops" aria-label="Permalink to “2. MLP 模块 FLOPs”">​</a></h4><h5 id="结构" tabindex="-1">结构： <a class="header-anchor" href="#结构" aria-label="Permalink to “结构：”">​</a></h5><ul><li>升维：$h \\to 4h$</li><li>GeLU 激活</li><li>降维：$4h \\to h$</li></ul><h5 id="flops-计算-1" tabindex="-1">FLOPs 计算： <a class="header-anchor" href="#flops-计算-1" aria-label="Permalink to “FLOPs 计算：”">​</a></h5><table tabindex="0"><thead><tr><th>操作</th><th>输入输出</th><th>FLOPs</th></tr></thead><tbody><tr><td>$[b,s,h] \\to [b,s,4h]$</td><td>$[b,s,h] \\times [h,4h]$</td><td>$2bs h \\cdot 4h = 8bsh^2$</td></tr><tr><td>$[b,s,4h] \\to [b,s,h]$</td><td>$[b,s,4h] \\times [4h,h]$</td><td>$2bs \\cdot 4h \\cdot h = 8bsh^2$</td></tr></tbody></table><blockquote><p>🔹 总计 MLP FLOPs： $$8bsh^2 + 8bsh^2 = 16bsh^2$$</p></blockquote><h3 id="_2-3-单层-transformer-总-flops" tabindex="-1">2.3 单层 Transformer 总 FLOPs <a class="header-anchor" href="#_2-3-单层-transformer-总-flops" aria-label="Permalink to “2.3 单层 Transformer 总 FLOPs”">​</a></h3><p>忽略轻微的逐元素操作（如 LayerNorm, Softmax, GeLU），单层前向传播总 FLOPs 为：</p><p>$$ \\text{FLOPs}_{\\text{forward_layer} } = 24bsh^2 + 4bs^2h $$</p><h3 id="_2-4-vocabulary-embedding-flops" tabindex="-1">2.4 Vocabulary Embedding FLOPs <a class="header-anchor" href="#_2-4-vocabulary-embedding-flops" aria-label="Permalink to “2.4 Vocabulary Embedding FLOPs”">​</a></h3><h4 id="操作" tabindex="-1">操作： <a class="header-anchor" href="#操作" aria-label="Permalink to “操作：”">​</a></h4><ul><li>将 token ID 映射为 embedding 向量</li><li>形状变换：$[b,s] \\to [b,s,h] \\to [b,s,V]$</li></ul><h4 id="flops" tabindex="-1">FLOPs： <a class="header-anchor" href="#flops" aria-label="Permalink to “FLOPs：”">​</a></h4><p>$$[b,s,h] \\times [h,V] \\Rightarrow 2bshV$$</p><blockquote><p>🔹 注意：此步骤通常只在前向传播中执行一次，但在反向传播中也有类似计算。</p></blockquote><h3 id="_2-5-模型总-flops" tabindex="-1">2.5 模型总 FLOPs <a class="header-anchor" href="#_2-5-模型总-flops" aria-label="Permalink to “2.5 模型总 FLOPs”">​</a></h3><p>假设 GPT 模型有 $L$ 层 Transformer 层，则：</p><table tabindex="0"><thead><tr><th>组件</th><th>FLOPs 公式</th></tr></thead><tbody><tr><td><strong>Self-Attention</strong></td><td>$8bsh^2 + 4bs^2h$</td></tr><tr><td><strong>MLP</strong></td><td>$16bsh^2$</td></tr><tr><td><strong>Embedding</strong></td><td>$2bshV$</td></tr><tr><td><strong>单个 Transformer</strong></td><td>$24bsh^2 + 4bs^2h$</td></tr><tr><td><strong>整模型总 FLOPs</strong></td><td>$L \\times (24bsh^2 + 4bs^2h) + 2bshV$</td></tr></tbody></table><h2 id="_3-反向传播与全流程计算" tabindex="-1">3. 反向传播与全流程计算 <a class="header-anchor" href="#_3-反向传播与全流程计算" aria-label="Permalink to “3. 反向传播与全流程计算”">​</a></h2><h3 id="_3-1-梯度计算原理" tabindex="-1">3.1 梯度计算原理 <a class="header-anchor" href="#_3-1-梯度计算原理" aria-label="Permalink to “3.1 梯度计算原理”">​</a></h3><p>在反向传播（Backward）中，对于每一个线性变换 $y = wx$，需要计算：</p><ul><li>对权重的梯度： $\\frac{\\partial L}{\\partial w} = \\frac{\\partial L}{\\partial y} \\cdot x$ → 一次矩阵乘法</li><li>对输入的梯度： $\\frac{\\partial L}{\\partial x} = \\frac{\\partial L}{\\partial y} \\cdot w$ → 一次矩阵乘法</li></ul><p><strong>结论</strong>：在训练中，反向传播的计算量约为前向传播的 <strong>2 倍</strong>。</p><h3 id="_3-2-训练总-flops" tabindex="-1">3.2 训练总 FLOPs <a class="header-anchor" href="#_3-2-训练总-flops" aria-label="Permalink to “3.2 训练总 FLOPs”">​</a></h3><p>包含前向和反向传播的单步总计算量约为：</p><p>$$ \\text{Total FLOPs} \\approx 3 \\times \\text{Forward FLOPs} $$</p><p>(注：若考虑重计算/激活值检查点 Recompute，倍数会增至约 4 倍)。</p><h3 id="_3-3-经验简化公式" tabindex="-1">3.3 经验简化公式 <a class="header-anchor" href="#_3-3-经验简化公式" aria-label="Permalink to “3.3 经验简化公式”">​</a></h3><p>对于大模型，当 $h \\gg s$ 时，公式可近似为：</p><p>$$ \\text{Total FLOPs} \\approx 72bsh^2L \\left(1 + \\frac{s}{6h} + \\frac{V}{12hL}\\right) $$</p><h2 id="_4-llama-系列模型的-mfu-特化计算" tabindex="-1">4. Llama 系列模型的 MFU 特化计算 <a class="header-anchor" href="#_4-llama-系列模型的-mfu-特化计算" aria-label="Permalink to “4. Llama 系列模型的 MFU 特化计算”">​</a></h2><p>Llama 模型在标准 Transformer 基础上引入了 <strong>GQA (Grouped Query Attention)</strong> 和 <strong>SwiGLU</strong> 激活函数，其计算分布略有不同。</p><h3 id="_4-1-模型结构简要说明" tabindex="-1">4.1 模型结构简要说明 <a class="header-anchor" href="#_4-1-模型结构简要说明" aria-label="Permalink to “4.1 模型结构简要说明”">​</a></h3><ul><li>使用 <strong>Llama2 架构</strong>：包含多层 Transformer 解码器</li><li>关键组件： <ul><li><strong>Attention 模块</strong>：含 RoPE、QKV 投影、Softmax、输出投影</li><li><strong>FeedForward 模块</strong>：含两个线性层与 Silu 激活函数</li><li><strong>RMSNorm</strong>：归一化操作</li><li><strong>lm_head</strong>：最终输出层</li></ul></li></ul><blockquote><p>📌 注意：<code>wq</code>, <code>wk</code>, <code>wv</code> 分别为 Q/K/V 的权重矩阵；<code>wo</code> 为输出投影；<code>w1</code>, <code>w2</code>, <code>w3</code> 为 FFN 中的权重。</p></blockquote><h4 id="_4-1-1-llama-架构差异点" tabindex="-1">4.1.1 Llama 架构差异点 <a class="header-anchor" href="#_4-1-1-llama-架构差异点" aria-label="Permalink to “4.1.1 Llama 架构差异点”">​</a></h4><ul><li><strong>GQA 影响</strong>：$K, V$ 的投影维度降为 $h/r$（$r$ 为 head 比例系数）。</li><li><strong>SwiGLU 影响</strong>：FFN 层由三个线性矩阵 $W_1, W_2, W_3$ 组成，中间维度为 $\\hat{h}$（通常为 $\\frac{8}{3}h$）。</li></ul><h4 id="_4-1-2-符号定义" tabindex="-1">4.1.2 符号定义 <a class="header-anchor" href="#_4-1-2-符号定义" aria-label="Permalink to “4.1.2 符号定义”">​</a></h4><table tabindex="0"><thead><tr><th>符号</th><th>含义</th></tr></thead><tbody><tr><td>$b$</td><td>batch_size</td></tr><tr><td>$L$</td><td>num_layers（层数）</td></tr><tr><td>$s$</td><td>seq_length（序列长度）</td></tr><tr><td>$h$</td><td>hidden_size（隐藏维度）</td></tr><tr><td>$n$</td><td>num_heads（注意力头数）</td></tr><tr><td>$d$</td><td>head_dim（每个头的维度）</td></tr><tr><td>$\\hat{h}$</td><td>intermediate_size（FFN 中间维度）</td></tr><tr><td>$v$</td><td>vocab_size（词表大小）</td></tr><tr><td>$r$</td><td>repeat（重复因子，通常为 $n / n_{kv}$）</td></tr><tr><td>$m$</td><td>ffn_dim_multiplier（FFN 扩展倍数，一般为 4）</td></tr></tbody></table><blockquote><p>🔹 关系式：</p><ul><li>$h = n \\times d$</li><li>$\\hat{h} \\approx \\frac{8}{3} h \\times m$</li></ul></blockquote><h3 id="_4-2-各模块-flops-详细分析" tabindex="-1">4.2 各模块 FLOPs 详细分析 <a class="header-anchor" href="#_4-2-各模块-flops-详细分析" aria-label="Permalink to “4.2 各模块 FLOPs 详细分析”">​</a></h3><h4 id="_1-attention-模块-×l-层" tabindex="-1">1. Attention 模块（×L 层） <a class="header-anchor" href="#_1-attention-模块-×l-层" aria-label="Permalink to “1. Attention 模块（×L 层）”">​</a></h4><table tabindex="0"><thead><tr><th>操作</th><th>输入 → 输出</th><th>FLOPs</th></tr></thead><tbody><tr><td>$W_q: (b,s,h) \\to (b,s,h)$</td><td>$[b,s,h] \\times [h,h]$</td><td>$2bsh^2$</td></tr><tr><td>$W_k: (b,s,h) \\to (b,s,h/r)$</td><td>$[b,s,h] \\times [h,h/r]$</td><td>$2bsh^2/r$</td></tr><tr><td>$W_v: (b,s,h) \\to (b,s,h/r)$</td><td>$[b,s,h] \\times [h,h/r]$</td><td>$2bsh^2/r$</td></tr><tr><td>$QK^T: (b,n,s,d) \\to (b,n,s,s)$</td><td>$[b,n,s,d] \\times [b,n,d,s]$</td><td>$2bs^2h$</td></tr><tr><td>$score \\cdot V: (b,n,s,s) \\to (b,n,s,d)$</td><td>$[b,n,s,s] \\times [b,n,d,s]$</td><td>$2bs^2h$</td></tr><tr><td>$W_o: (b,s,h) \\to (b,s,h)$</td><td>$[b,s,h] \\times [h,h]$</td><td>$2bsh^2$</td></tr></tbody></table><blockquote><p>✅ 总计 Attention FLOPs（每层）： $$2bsh^2 + \\frac{2bsh^2}{r} + \\frac{2bsh^2}{r} + 2bs^2h + 2bs^2h + 2bsh^2 = 4bsh^2 + \\frac{4bsh^2}{r} + 4bs^2h$$</p></blockquote><h4 id="_2-feedforward-模块-×l-层" tabindex="-1">2. FeedForward 模块（×L 层） <a class="header-anchor" href="#_2-feedforward-模块-×l-层" aria-label="Permalink to “2. FeedForward 模块（×L 层）”">​</a></h4><table tabindex="0"><thead><tr><th>操作</th><th>输入 → 输出</th><th>FLOPs</th></tr></thead><tbody><tr><td>$W_3: (b,s,h) \\to (b,s,\\hat{h})$</td><td>$[b,s,h] \\times [h,\\hat{h}]$</td><td>$2bsh\\hat{h}$</td></tr><tr><td>$W_1: (b,s,h) \\to (b,s,\\hat{h})$</td><td>$[b,s,h] \\times [h,\\hat{h}]$</td><td>$2bsh\\hat{h}$</td></tr><tr><td>$W_2: (b,s,\\hat{h}) \\to (b,s,h)$</td><td>$[b,s,\\hat{h}] \\times [\\hat{h},h]$</td><td>$2bsh\\hat{h}$</td></tr></tbody></table><blockquote><p>✅ 总计 FFN FLOPs（每层）： $$6bsh\\hat{h}$$</p></blockquote><h4 id="_3-lm-head-模块" tabindex="-1">3. lm_head 模块 <a class="header-anchor" href="#_3-lm-head-模块" aria-label="Permalink to “3. lm_head 模块”">​</a></h4><table tabindex="0"><thead><tr><th>操作</th><th>输入 → 输出</th><th>FLOPs</th></tr></thead><tbody><tr><td>$W_{head}: (b,s,h) \\to (b,s,v)$</td><td>$[b,s,h] \\times [h,v]$</td><td>$2bshv$</td></tr></tbody></table><blockquote><p>✅ 注意：该操作仅在最后一步执行，但对总 FLOPs 贡献显著。</p></blockquote><h3 id="_4-3-总-flops-推导" tabindex="-1">4.3 总 FLOPs 推导 <a class="header-anchor" href="#_4-3-总-flops-推导" aria-label="Permalink to “4.3 总 FLOPs 推导”">​</a></h3><h4 id="_4-3-1-前向传播总-flops-单次" tabindex="-1">4.3.1 前向传播总 FLOPs（单次） <a class="header-anchor" href="#_4-3-1-前向传播总-flops-单次" aria-label="Permalink to “4.3.1 前向传播总 FLOPs（单次）”">​</a></h4><p>$$\\text{FLOPs} = L \\times \\left[ 4bsh^2 + \\frac{4bsh^2}{r} + 4bs^2h + 6bsh\\hat{h} \\right] + 2bshv$$</p><p>代入 $\\hat{h} \\approx \\frac{8}{3}hm$，并简化：</p><p>$$= 12Lbsh^2 \\left(1 + \\frac{1}{r} + \\frac{3\\hat{h} }{2h} + \\frac{s}{h} + \\frac{v}{2Lh}\\right)$$</p><p>进一步近似：</p><ul><li>$\\frac{3\\hat{h} }{2h} \\approx 4m$</li><li>$\\frac{1}{r} \\approx \\frac{n}{n_{kv} }$，常忽略或合并</li></ul><blockquote><p>✅ 最终简化公式： $$\\text{FLOPs} \\approx 12Lbsh^2 \\left(1 + \\frac{1}{r} + 4m + \\frac{s}{h} + \\frac{v}{2Lh}\\right)$$</p></blockquote><h4 id="_4-3-2-反向传播-flops" tabindex="-1">4.3.2 反向传播 FLOPs <a class="header-anchor" href="#_4-3-2-反向传播-flops" aria-label="Permalink to “4.3.2 反向传播 FLOPs”">​</a></h4><ul><li>反向传播 FLOPs ≈ <strong>前向的 2 倍</strong></li><li>因此，<strong>总训练 FLOPs ≈ 3 × 前向 FLOPs</strong></li></ul><blockquote><p>💡 提示：MFU 计算时需使用总 FLOPs（前向 + 反向 + 优化器），但此处以前向为主进行估算。</p></blockquote><h3 id="_4-4-实例分析-llama2-70b" tabindex="-1">4.4 实例分析：Llama2-70B <a class="header-anchor" href="#_4-4-实例分析-llama2-70b" aria-label="Permalink to “4.4 实例分析：Llama2-70B”">​</a></h3><p>给定参数：</p><ul><li>$s = 4096$</li><li>$h = 8192$</li><li>$L = 80$</li><li>$r = 8$</li><li>$\\hat{h} = 28672$</li><li>$v = 32000$</li></ul><p>代入公式：</p><p>$$\\text{FLOPs} \\approx 12 \\times 80 \\times b \\times 8192^2 \\left(1 + \\frac{1}{8} + 4 \\times 4 + \\frac{4096}{8192} + \\frac{32000}{2 \\times 80 \\times 8192}\\right)$$</p><blockquote><p>🔸 近似可得： $$\\text{FLOPs} \\approx 6bs \\times (\\text{总参数量} + 2Lsh)$$</p></blockquote><p>对于 70B 模型，由于参数量极大，其 $6bs \\times \\text{Params}$ 的估算方法非常接近精确值。在计算 MFU 时，需精确代入 $h=8192$ 和 $\\hat{h}=28672$ 等超参数，以获得准确的算力需求分析。</p><h2 id="_5-总结与优化建议" tabindex="-1">5. 总结与优化建议 <a class="header-anchor" href="#_5-总结与优化建议" aria-label="Permalink to “5. 总结与优化建议”">​</a></h2><table tabindex="0"><thead><tr><th><strong>优化方向</strong></th><th><strong>操作手段</strong></th><th><strong>对 MFU 的影响</strong></th></tr></thead><tbody><tr><td><strong>计算密度</strong></td><td>增大 Batch Size</td><td>显著提升，减少算子调度和通信开销</td></tr><tr><td><strong>通信优化</strong></td><td>调整 TP/PP 比例</td><td>降低通信延迟，减少算力闲置</td></tr><tr><td><strong>算子融合</strong></td><td>使用 FlashAttention</td><td>降低显存带宽压力，提高计算利用率</td></tr><tr><td><strong>精度转换</strong></td><td>使用 BF16/FP8</td><td>提升单位时间内的理论吞吐量</td></tr></tbody></table><blockquote><p><strong>专家目标</strong>：在千卡规模的集群训练中，将 MFU 稳定在 <strong>55% - 70%</strong> 是大模型训练达到工业级性能的标志。</p></blockquote>',95)])])}const m=a(h,[["render",d]]);export{c as __pageData,m as default};
